#[test]
fn jax_core_laplace_covariance_from_jacobian() {
    let fixture = load_fixture();
    for (i, case) in fixture["laplace_covariance_from_jacobian"]
        .as_array()
        .unwrap()
        .iter()
        .enumerate()
    {
        let inp = &case["inputs"];
        let exp = &case["outputs"];
        let j_rows = mat_f(&inp["jacobian"]);
        let j: Vec<[f64; 2]> = j_rows.iter().map(|row| [row[0], row[1]]).collect();
        let cov = laplace_covariance_from_jacobian(&j, f(&inp["noise_variance"]))
            .expect("non-singular");
        let expected = mat_f(&exp["covariance"]);
        for r in 0..2 {
            for c in 0..2 {
                assert_close(
                    cov[r][c],
                    expected[r][c],
                    LIBM,
                    &format!("laplace_covariance_from_jacobian[{i}][{r}][{c}]"),
                );
            }
        }
    }
}

